var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 9월 26일 런던, 화이트 채플\\n<color=#ffd34c>심야</color>","JPN":"1888年9月26日　ロンドン、ホワイトチャペル\\n<color=#ffd34c>深夜</color>","ENG":"September 26, 1888, London, White Chapel,\\n<color=#ffd34c>Midnight</color>","TWN":"1888年9月26日 倫敦，白教堂\\n<color=#ffd34c>深夜</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WITHMESS_SWANSONG_NPC_A","text":{"KOREA":"벌써 한 달 정도 지난 일이라 잘 기억은 안 나지만…….","JPN":"もう一か月も前だからおぼろげだけど……","ENG":"I don't remember clearly because it's been about a month...","TWN":"已經過一個月了，我記不太清了……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WITHMESS_SWANSONG_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WITHMESS_SWANSONG_NPC_A","text":{"KOREA":"아! 그래요. 죽은 시체 옆에 백묵으로 <color=#ffd34c>낙서</color>가 쓰여 있었어요.","JPN":"ああ、そうだ。死体の横に、チョークで書かれた<color=#ffd34c>落書き</color>がありました。","ENG":"Oh! Yes. There were <color=#ffd34c>writings</color> next to the corpse in chalk.","TWN":"啊！對了。屍體旁邊用白粉筆寫了某些<color=#ffd34c>塗鴉</color>。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WITHMESS_SWANSONG_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WITHMESS_SWANSONG_NPC_A","text":{"KOREA":"그게 무슨 낙서였더라…….","JPN":"なんて書いてあったっけ……","ENG":"Now, what was it...?","TWN":"那是什麼來著……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WITHMESS_SWANSONG_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WITHMESS_SWANSONG_NPC_B","text":{"KOREA":"시체는 날카로운 날붙이 같은 것으로 <color=#ffd34c>신체 일부</color>가 훼손되어 있었소.","JPN":"死体は刃物みたいなもので<color=#ffd34c>体の一部</color>が傷つけられていた。","ENG":"<color=#ffd34c>A part of the body</color> was cut from the corpse with what looked like a sharp blade.","TWN":"<color=#ffd34c>身體的一部分</color>被鋒利的刀具破壞了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WITHMESS_SWANSONG_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WITHMESS_SWANSONG_NPC_B","text":{"KOREA":"내가 봤던 두 번째 희생자의 경우…….","JPN":"俺が見た二人目の犠牲者は……","ENG":"As for the second victim I saw...","TWN":"我看到的第二個受害者的情況就是這樣……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WITHMESS_SWANSONG_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WITHMESS_SWANSONG_NPC_C","text":{"KOREA":"그날 밤에 덩치가 크고, 검은 갑옷을 입고 있는 사람을 봤어요.","JPN":"あの夜、体が大きくて黒い鎧を来ている人を見ました。","ENG":"That night, I saw a large person wearing black armor.","TWN":"那天晚上，我看到一個身材高大，穿著黑色盔甲的人。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WITHMESS_SWANSONG_NPC_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WITHMESS_SWANSONG_NPC_C","text":{"KOREA":"한 눈을 판 사이에 어디론가 사라져 버렸지만……. 정말이에요. 제가 똑똑히 봤다고요!","JPN":"ちょっとよそ見してる間にどこかに消えてしまったけど……本当です。確かに見たんです！","ENG":"I looked away for a second and no one was there... I'm telling you the truth! I know what I saw!","TWN":"一眨眼的功夫就不見了……真的，我看得清清楚楚！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WITHMESS_SWANSONG_NPC_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"벌써 동이 트기 시작했군. 아무래도 오늘 밤 조사는 여기서 마치도록 하지.","JPN":"もう夜が明ける時間だな。今夜の調査はここまでにしよう。","ENG":"The sun is about to rise. Let's end our investigation here for tonight.","TWN":"天已經快亮了。今晚的調查就到這裡好了。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 이쯤에서 수집한 정보를 정리해 보도록 할까?","JPN":"では今まで集めた情報をまとめてみるか。","ENG":"Then, shall we try to summarize the information we've collected so far?","TWN":"那麼，讓我們整理一下收集到的資訊吧？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"되도록 일목요연하게 부탁하지, 스완.","JPN":"スワン、なるべく一目瞭然にまとめてくれ。","ENG":"Please make it as clear as possible, Swan.","TWN":"請儘量簡明扼要，史旺。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"흥, 빨리 끝내고 싶은 건 저도 마찬가지라고요.","JPN":"ふん、早く終わらせたいのは私も同じなんですよ。","ENG":"Hmph. I also want to end this quickly.","TWN":"哼，我也想快點結束。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"흠흠……!","JPN":"ごほん……！","ENG":"Ahem...!","TWN":"咳嗯……！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마가 저지른 두 사건에는 <color=#ffd34c>공통점</color>이 있었어요.","JPN":"深夜の殺人鬼が犯した二つの事件には<color=#ffd34c>共通点</color>があります。","ENG":"The two incidents committed by the Midnight Killer have a few <color=#ffd34c>commonalities</color>.","TWN":"午夜殺人魔犯下的兩起案件有幾個<color=#ffd34c>共同點</color>。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"날카로운 금속 날붙이로 범행을 저지른 점, 신체 중 일부가 유독 심하게 훼손되었다는 점.","JPN":"凶器は鋭い金属の刃物だという点、体の一部がひどく損傷していた点。","ENG":"One is that a sharp metal blade was used, and another is that the certain parts of the body were mutilated.","TWN":"兇手用鋒利的金屬刀具作案，並且受害人身體的某些部位被特別嚴重地破壞了。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 현장에는 의미를 알 수 없는 낙서가 있었다는 점이죠.","JPN":"そして現場に意味不明な落書きが残されていた点ですね。","ENG":"Also, there was a writing of some sort left behind on the scene.","TWN":"另外，現場還有一些無法理解的塗鴉。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"나쁘지 않군.","JPN":"悪くない。","ENG":"Not bad.","TWN":"不錯。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"개요는 그 정도면 충분해. 이번에는 피해자에 대해 한 번 정리해보겠나?","JPN":"概要はそれで十分だ。今度は被害者の情報をまとめてくれるか？","ENG":"That's enough of an overview. Could you summarize the victims this time?","TWN":"概括就到這裡吧。這次能整理一下受害者的情況嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"먼저, 첫 번째 희생자는 모자 가게에서 일하던 마리 앤 니콜스.","JPN":"一人目の犠牲者は、帽子屋で働いていたマリ・アン・ニコルス。","ENG":"The first victim was Marie Ann Nicholes who worked at a hat shop.","TWN":"首先，第一個受害者是帽子店工作的瑪麗安·尼科爾斯。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"나이는 17세. 생일은 6월 30일. <color=#ffd34c>흉부</color>가 훼손되어 있었죠.","JPN":"6月30日生まれの17歳。<color=#ffd34c>胸部</color>が損傷していました。","ENG":"Seventeen years old. Born on June 30th. And had her <color=#ffd34c>chest</color> mutilated.","TWN":"年齡是17歲。生日是6月30日。被破壞部位為<color=#ffd34c>胸部</color>。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"증언에 따르면, 현장에 남아 있던 낙서는…….","JPN":"証言によると、現場に残されていた落書きは……","ENG":"According to witness statements, the writing left on the scene is...","TWN":"根據證詞，現場留下的塗鴉是……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>그녀가 첫 번째 시련을 지나, 내게 오게 하노라. 그녀는 은과 같이 되리라.</color>","JPN":"<color=#ffd34c>彼女が一つ目の試練を越え、私へと向かわせる。彼女は銀のようになるだろう。</color>","ENG":"<color=#ffd34c>Let her come through the first ordeal to me. And she will be as silver.</color>","TWN":"<color=#ffd34c>讓她經歷第一之裁判吧。來到我面前，她將如銀一般純淨。</color>"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"으음, 글쎄요. 이게 무슨 뜻인지는 잘 모르겠네요.","JPN":"うーん。この言葉の意味はよくわかりませんね。","ENG":"Hmm, well. I'm not sure what that's supposed to mean.","TWN":"嗯，不好說。這是什麼意思我也不太清楚。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 두 번째 희생자. 가정부였던 허니 채프먼.","JPN":"そして二人目の犠牲者。家政婦として働いていたハニー・チャップマン。","ENG":"And our second victim was a housewife named Honey Chapman.","TWN":"然後是第二個受害者，曾是女傭的哈妮·查普曼。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"나이는 21세. 생일은 1월 23일. 오른쪽 <color=#ffd34c>무릎</color>이 훼손되었죠.","JPN":"1月23日生まれの21歳。右側の<color=#ffd34c>膝</color>が損傷していました。","ENG":"Twenty-one years old. Born on January 23rd. Her right <color=#ffd34c>knee</color> was severely damaged.","TWN":"年齡21歲。生日是1月23日。被破壞的部位是右側的<color=#ffd34c>膝蓋</color>。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"현장의 낙서는 <color=#ffd34c>두 번째 시련을 지나라. 그녀는 납과 같이 견고해지리라.</color>","JPN":"現場の落書きには<color=#ffd34c>二つ目の試練を越えろ。彼女は鉛のように堅固になるだろう。</color>","ENG":"The writing read: <color=#ffd34c>Go through the second ordeal. For she will be sturdy like lead.</color>","TWN":"現場的塗鴉是<color=#ffd34c>經歷第二之裁判。她將堅固如鉛。</color>"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……뭐, 중요한 사항은 이 정도겠죠.","JPN":"……まあ、重要な証言はこの程度ですね。","ENG":"...Well, that should be all of the important things.","TWN":"……嗯，重要事項大概就是這些了吧。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"좋아, 역시나 잘 기억하고 있군.","JPN":"いいぞ。さすがよく覚えているな。","ENG":"All right. Wonderful memory you've got.","TWN":"不錯，你果然記得很清楚。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래서? 뭘 좀 알아내셨나요?","JPN":"で、何か気づいたことはあるんですか？","ENG":"So? Did you find out anything?","TWN":"所以？你查到什麼了嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"프리마돈나인 저에게 이런 조수 역할이나 시켜놓고, 모르겠다고는 안 하겠죠?","JPN":"プリマドンナの私にここまで手伝わせておいて、何もわからないとは言わせませんよ。","ENG":"You're not going to say that you don't know after making a prima donna act as your assistant, right?","TWN":"讓身為首席演員的我做這種助手的工作，你不會要說你不知道吧？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 물론이야.","JPN":"ふふ、無論だ。","ENG":"Haha, of course, not.","TWN":"呵呵，當然。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"적어도 심야의 살인마가 어떤 이유로 시체를 훼손하는지는 알 것 같군.","JPN":"少なくとも、深夜の殺人鬼がどんな理由で死体を損傷したかはわかる気がするな。","ENG":"I think I know why the Midnight Killer is mutilating corpses, at least.","TWN":"至少我知道午夜殺人魔為什麼要毀壞屍體了。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"흥, 역시 허풍이 심하시네요.","JPN":"ふん、大言壮語も大概にしてください。","ENG":"Hmph. I'll call that bluff.","TWN":"哼，果然是個大吹牛皮的傢伙。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"고작 증언 몇 번 들은 걸로, 대체 어떻게…….","JPN":"証言を少し聞いただけで、どうやって……","ENG":"With just a few statements, how could you–","TWN":"就憑幾句證詞，究竟是怎麼……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"간단한 이야기라네. 스완.","JPN":"簡単な話だよ、スワン。","ENG":"It's elementary, my dear Swan.","TWN":"很簡單的推理，親愛的史旺。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이곳에 오기 전 심야의 살인마가 공표했던 성명문의 내용을 한 번 떠올려 보게.","JPN":"ここに来る前、深夜の殺人鬼が公表した声明文を読んだだろう。あれを思い出してみるんだ。","ENG":"Try to remember what the statement the Midnight Killer sent said before we got here.","TWN":"在來到這裡之前，午夜殺手發表的聲明內容，你還記得嗎。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"성명문이라고요?","JPN":"声明文ですか？","ENG":"The statement?","TWN":"聲明？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 성명문에서 심야의 살인마는 이능력자를 노린다고 했어.","JPN":"ああ、声明文で深夜の殺人鬼は自分が異能力者を狙っていると言っていた。","ENG":"Yes. His statement said that he was after Supernaturals.","TWN":"對，聲明中說午夜殺手專門針對超能力者。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 그들의 <color=#ffd34c>표식</color>을 쫓아 전부 잘라낸다고 했지.","JPN":"そして彼らの<color=#ffd34c>印</color>をすべて切り落とすとも言っていたな。","ENG":"And that he would find and cut out their <color=#ffd34c>marks</color>.","TWN":"而且他會追蹤他們<color=#ffd34c>標記</color>，直到將其全部切除。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네도 이능력자니까 알고 있겠지? 표식의 의미를 말이야.","JPN":"君も異能力者だから知っているだろう？　その印の意味を。","ENG":"You should also know the meaning of the mark as you're also a Supernatural.","TWN":"你也是超能力者，應該知道這個標記的意義吧？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"흥, 그 정도는 저도 알고 있다고요.","JPN":"ふん、それぐらいは私にもわかります。","ENG":"Hmph. Of course, I do.","TWN":"哈，這我當然知道。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이능력자들은 어떤 경로로든 저마다 <color=#ffd34c>증표</color>를 얻게 되고.","JPN":"異能力者はどんな方法であれ、それぞれ<color=#ffd34c>印</color>を手にすることになります。","ENG":"Supernaturals each obtain a <color=#ffd34c>mark</color> of their own.","TWN":"這些超能力者無論透過什麼途徑，都會獲得各自的<color=#ffd34c>象徵</color>。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그 증표로부터 이능력을 부여받게 된다는 걸.","JPN":"そして、その印によって異能力を与えられるのです。","ENG":"It's the mark that grants them their powers.","TWN":"並且從這些象徵中獲取異能。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저의 경우 그 증표는 이 <color=#ffd34c>회중 시계</color>.","JPN":"私の場合、印はこの<color=#ffd34c>懐中時計</color>。","ENG":"For me, that mark is this <color=#ffd34c>pocket watch</color>.","TWN":"對我來說，這個象徵就是這支<color=#ffd34c>懷錶</color>。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"어렸을 때, 조부께서 남겨 주신 물건이었어요. 그때는 이게 증표인지 몰랐지만.","JPN":"幼い頃、祖父に譲り受けたものです。あの頃はこれが印だとは知りませんでしたけど。","ENG":"It was something my grandfather left me when I was little. But at the time, I didn't know it was a mark.","TWN":"小時候，祖父留給我的東西。但當時我還並不知道。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 증표는 저마다 자연스러운 방식으로 습득하게 된다고 알려져 있으니까.","JPN":"ああ、印はそれぞれの異能力者が、自然な方法で取得すると言われているな。","ENG":"Yes. It's known that people receive their marks naturally in their own way.","TWN":"是的，據說每個超能力者都會以某種自然的方式獲得象徵。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래서? 증표가 사건과 무슨 관련이 있다는 거죠? 시계를 잘라낼 수는 없잖아요?","JPN":"それで、その印が事件となんの関係があるんですか？　時計を切り落とすなんて、おかしいです。","ENG":"So? What does the mark have to do with the case? He can't cut off my pocket watch.","TWN":"所以呢？這和事件有什麼關係嗎？他總不能剪掉我的懷錶吧？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐, 잘라낸다고? 설마……?","JPN":"……待って、切り落とす……？　まさか……？","ENG":"Wait, cut off? Could it be...?","TWN":"等等，剪掉？難道……？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그동안 여러 사건을 해결해 오면서 이능력자에 대해 알게 된 게 있다네.","JPN":"今までいくつもの事件を解決してきて、異能力者についてわかったことがある。","ENG":"While solving various cases, I learned something about Supernaturals.","TWN":"在解決許多案件的過程中，我了解到了一些關於超能力者的事情。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네처럼 어떤 물건과 접촉한 것을 계기로 이능력자가 되는 케이스도 있지만.","JPN":"君のように、ある物に接触したことがきっかけで異能力者になるケースもあるが……","ENG":"There are some, like you, who got special powers by coming into contact with an object.","TWN":"像你這樣通過接觸某些物品而成為超能力者的情況也是有的。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"때때로 어느 날 갑자기 신체에 반점처럼 발현되는 증표도 있다는 걸 말이야.","JPN":"ある日突然、身体に斑点のように現れる印も存在するのだ。","ENG":"And there are also those who have had marks suddenly appear on their bodies.","TWN":"但也有身體上直接出現某種印記的情況。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다는 말은……!","JPN":"ということは……！","ENG":"Then that means...!","TWN":"那就是說……！"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마가 희생자들의 <color=#ffd34c>신체에 발현된 증표를 가져가려고</color> 시체를 훼손하고 있다는 뜻인가요?","JPN":"深夜の殺人鬼は、犠牲者たちの<color=#ffd34c>体に発現した印を奪うために</color>死体を傷つけているということですか？","ENG":"The Midnight Killer is mutilating the victims' corpses <color=#ffd34c>to obtain the marks that appeared on their bodies</color>?","TWN":"午夜殺人魔是為了拿走受害者<color=#ffd34c>身體上顯現的標記</color>，才破壞屍體的嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 이해가 빨라서 좋군.","JPN":"ああ、理解が早くて助かるよ。","ENG":"Yes. I'm glad you understand quickly.","TWN":"是的，你理解得很快，真不錯。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그런 방식으로 접근한다면 범인이 남긴 낙서도 다른 관점에서 볼 수 있어.","JPN":"その筋読みからもう一歩踏み出せば、犯人が残した落書きも違う角度から見ることができるだろう。","ENG":"If we approach it like that, the writings he left can be seen from a different perspective.","TWN":"如果以那種方式來思考的話，也許能從另一個角度看待兇手留下的塗鴉。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"다른 관점이라면, 어떤……?","JPN":"違う角度とは、どんな……？","ENG":"A different perspective? Like what...?","TWN":"另一個角度的話，是指……？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"여기까지 했으면 설명은 충분할 텐데? 한 번쯤 자네도 머리를 써보는 게 어떨까?","JPN":"ここまで話せば説明は十分なはずだが？　一度ぐらい君も自分で考えてみるのはどうかね？","ENG":"Shouldn't my explanation thus far be enough? How about you use your brain this time?","TWN":"解釋到這個地步應該已經足夠了吧？你也該動動腦子了，如何？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"큿! 그럼 그렇지!","JPN":"くっ……！　そうやってまた……！","ENG":"Krgh! I knew it!","TWN":"咳！果然如此！"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"좋아, 내가 못할 줄 알고……!?","JPN":"いいわ、私にだってわかるはず……！","ENG":"All right. You don't think I can do it...?!","TWN":"好，難道你以為我做不到嗎……？！"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"첫 번째 시련은…… 그녀가 은과 같이 되리라.","JPN":"一つ目の試練……彼女は銀のようになるだろう。","ENG":"The first ordeal... She will be as silver.","TWN":"第一之裁判……她將如銀一般純淨。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"두 번째 시련은 그녀가 납과 같이 견고해지리라…….","JPN":"二つ目の試練……彼女は鉛のように堅固になるだろう。","ENG":"The second ordeal, she will be sturdy like lead...","TWN":"第二之裁判，她將堅固如鉛……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"시련은 결과가 아니야. 과정이지.","JPN":"試練は結果じゃない、過程。","ENG":"The ordeals aren't the results, they are the process.","TWN":"裁判不是結果，而是某種試煉的過程。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그리고……. 그 결과가 은과 납이라면…….","JPN":"そして……その結果が銀と鉛というなら……","ENG":"And... if the results are silver and lead...","TWN":"然後……如果得到的是銀和鉛的話……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇군요!","JPN":"そうだったのね！","ENG":"I get it now!","TWN":"原來如此！"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이 낙서는 어떠한 <color=#ffd34c>절차</color>를 뜻하고 있는 거예요.","JPN":"あの落書きは、何かの<color=#ffd34c>手順</color>を表してるんです。","ENG":"Those writings refer to a certain <color=#ffd34c>process</color>.","TWN":"這些塗鴉暗示了某種<color=#ffd34c>程序</color>！"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마는 정해진 절차에 따라 희생자들의 증표를 회수하고 있는 거죠.","JPN":"深夜の殺人鬼は決められた手順に従って……犠牲者たちの印を回収してる。そういうことですね？","ENG":"The Midnight Killer is collecting the marks of his victims according to a certain order.","TWN":"午夜殺人魔正在按照既定程序回收受害者的標記！"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 그래서 의식이라고 했던 건가……?","JPN":"ああ、だから儀式って言ったのかしら……？","ENG":"Yes. Is that why you said it was like a ritual...?","TWN":"沒錯，所以你才說是某種儀式……？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"은과 납. 이 키워드에 맞는 메타포를 찾아낸다면…….","JPN":"銀と鉛。このキーワードに当たるメタファーを探し出せれば……","ENG":"Silver and lead. If I can find a metaphor that uses those two as keywords...","TWN":"銀和鉛。如果能找到符合這兩個關鍵字的隱喻……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"어쩌면 심야의 살인마보다도 앞질러서 범행을 막을 수 있을지도 몰라요.","JPN":"先回りして、深夜の殺人鬼の犯行を止めることができるかもしれません。","ENG":"Maybe we can stop the Midnight Killer before he commits another murder.","TWN":"或許能比午夜殺人魔更早阻止犯罪。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 정답이야.","JPN":"ふふ、正解だ。","ENG":"Haha. That's correct.","TWN":"哈哈，答對了。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"역시 자네는 소질이 있군. 내 눈은 틀리지 않았어.","JPN":"やはり君には素質がある。私の目に狂いはなかったようだ。","ENG":"I knew you showed potential. My eyes are never wrong.","TWN":"果然你很有天賦。我的眼光沒有錯。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……흐, 흐응!","JPN":"……ふ、ふん！","ENG":"...H-hmph!","TWN":"……哼！"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"또 마음에도 없는 소리를! 협박범한테 칭찬받아도 전혀 기쁘지 않다고요!","JPN":"また心にもないことを！　脅迫犯に褒められてもまったく嬉しくありませんから！","ENG":"Again with your nonsense! I'm not happy at all to be praised by a blackmailer like you!","TWN":"又在說好聽話！被你這種威脅犯誇獎一點也高興不起來！"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그 절차를 알아내는 것보다 한 발 앞서 생각해 봐야 할 점이 있다네.","JPN":"だが、その手順を究明するより先に、考えるべきことがある。","ENG":"There is one thing we need to think about in advance before finding out this procedure of his.","TWN":"但是比起解開那個程式，有一點需要先考慮一下。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"바로 정보의 입수 경로지.","JPN":"情報の入手ルートだ。","ENG":"That is a route to obtain information.","TWN":"那就是資訊的獲取途徑。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"정보의 입수 경로라고요?","JPN":"情報の入手ルートですか？","ENG":"A route to obtain information?","TWN":"資訊的獲取途徑？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이곳 런던은 이능력자들을 혐오하는 동시에 두려워하고 있어.","JPN":"このロンドンの人々は異能力者を嫌悪し、同時に恐れている。","ENG":"In London, Supernaturals are both hated and feared.","TWN":"超能力者在倫敦被恐懼被憎恨。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그림자 사태로 인해, 그들은 언제 터질지 모르는 시한폭탄 같은 존재가 되어버렸으니까.","JPN":"シャドウ事変によって、異能力者はいつ爆発するかわからない時限爆弾のような存在になってしまったからね。","ENG":"Due to the Shadow incident, the public sees them as walking time bombs.","TWN":"由於暗影事件，他們成了隨時可能爆炸的定時炸彈。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그들도 원해서 이능력자가 된 게 아니야. 그러니 정체를 숨길 수밖에 없지.","JPN":"だが、彼らとて好きで異能力者になったわけではない。だから正体を隠すしかない。","ENG":"But those people didn't obtain special powers because they wanted to. So, they have no choice but to hide it.","TWN":"但他們也不是自願成為超能力者的。所以只能隱藏身份。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마는 그 음지로 숨어든 이능력자들에 대한 정보를 훤히 꿰뚫고 있어.","JPN":"深夜の殺人鬼は、この世界の陰に潜んでいる異能力者の情報を知り尽くしている。","ENG":"The Midnight Killer already has all the information he needs about those hiding their special powers.","TWN":"但午夜殺人魔對那些隱藏身份的超能力者卻瞭若指掌。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇군요. 절차에 맞는 희생자를 골라내기 위해서…….","JPN":"そうですね。一連の手順に適合した犠牲者を選別するために……","ENG":"I see. The Midnight Killer is targeting victims who fit the procedure...","TWN":"原來如此。為了挑選符合程式的犧牲者……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마는 이능력자들 중에서도 <color=#ffd34c>신체에 증표가 새겨진</color> 이들을 노리고 있으니까.","JPN":"深夜の殺人鬼は異能力者の中でも<color=#ffd34c>体に印がある</color>者を特定しなければならない。","ENG":"And the victims are Supernaturals <color=#ffd34c>with a mark on their bodies</color>.","TWN":"午夜殺人魔會專門盯上那些<color=#ffd34c>身體上有著印記</color>的超能力者。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"결국, 심야의 살인마가 어떤 경로로 타겟에 대한 정보를 손에 넣었는지가 관건이겠지.","JPN":"つまり、深夜の殺人鬼がどんなルートでターゲットの情報を入手しているのかが鍵になるだろう。","ENG":"In the end, the key will be in how the Midnight Killer obtained information about his target.","TWN":"沒錯，最終，關鍵在於午夜殺人魔通過什麼途徑獲取了目標的資訊。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이렇게 짧은 시간에, 이런 단편적인 정보로 거기까지 내다보다니…….","JPN":"こんな短時間で、断片的な情報だけでそこまで把握するとは……","ENG":"Being able to see that far in such a short period of time with only bits of information...","TWN":"在這麼短的時間內，憑藉這些零碎的資訊就能看得這麼遠……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"분하지만, 역시 인정할 수밖에 없네요.","JPN":"悔しいけど、認めざるを得ませんね。","ENG":"It angers me, but I have to admit this.","TWN":"雖然不甘心，但還是不得不承認。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"틀림없이 유능한 사람이에요, 당신은.","JPN":"あなたは、本当に有能な人です。","ENG":"You really are good at what you do.","TWN":"毫無疑問，你是個非常有能力的人。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그 유능함을 쓸데없는 곳에 낭비하는 괴짜지만…….","JPN":"その有能さを無駄遣いするような変わり者でもありますが……","ENG":"Even if you are an odd one to waste such talents on trivial matters...","TWN":"不過你總是把能力浪費在無用的地方……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 말하지 않았나?","JPN":"ふふ、だから言っただろう？","ENG":"Haha. Didn't I say?","TWN":"呵呵，我沒說過嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 어떤 사건이든 철저하고 낱낱이 규명하는 게 나의 업이라고.","JPN":"どんな事件も徹底的に暴き、疑問一つ残らず突き詰めることが私の仕事だと。","ENG":"It's my job to thoroughly investigate and identify things no matter the case.","TWN":"徹底調查每一個案件，是我的職責。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 누구나 자신의 업과 마주할 때가 오게 되지.","JPN":"そして誰もが、自分のなすべきことに向き合う時が来るのさ。","ENG":"Also, there comes a time when everyone faces their own work.","TWN":"而且，每個人都會有面對自己職責的時候。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"기억하게, 스완.","JPN":"覚えておきたまえ、スワン。","ENG":"Remember, Swan.","TWN":"記住，史旺。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"세상에서 제일 두려운 것은, 자기 자신이 원하는 게 뭔지 모르는 것이라는 걸.","JPN":"この世で一番恐ろしいことは、自分自身が何を望んでいるかわからなくなることだ。","ENG":"The most fearful thing in the world is not knowing what you want.","TWN":"世界上最可怕的事情就是不知道自己想要什麼。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};